
          const TOTAL = 12;
          let current = 0;
          let auto = true;
          let timer = null;
          const DELAYS = [4000, 5000, 5000, 6000, 6000, 6000, 6000, 7000, 6000, 5000, 15000, 8000];

          const scenes = document.querySelectorAll('.scene');
          const dots = document.getElementById('nav-dots');
          const progress = document.getElementById('progress-bar');
          const counter = document.getElementById('scene-counter');

          // Create nav dots
          for (let i = 0; i < TOTAL; i++) {
            const d = document.createElement('div');
            d.className = 'nav-dot' + (i === 0 ? ' active' : '');
            d.onclick = () => goTo(i);
            dots.appendChild(d);
          }

          // Create particles
          const stage = document.getElementById('stage');
          for (let i = 0; i < 20; i++) {
            const p = document.createElement('div');
            p.className = 'particle';
            p.style.left = Math.random() * 100 + '%';
            p.style.animationDuration = (5 + Math.random() * 10) + 's';
            p.style.animationDelay = (Math.random() * 10) + 's';
            p.style.width = p.style.height = (1 + Math.random() * 3) + 'px';
            stage.appendChild(p);
          }

          function goTo(n) {
            scenes[current].classList.remove('active');
            document.querySelectorAll('.nav-dot')[current].classList.remove('active');
            current = (n + TOTAL) % TOTAL;
            scenes[current].classList.add('active');
            document.querySelectorAll('.nav-dot')[current].classList.add('active');
            counter.textContent = String(current + 1).padStart(2, '0') + ' / ' + String(TOTAL).padStart(2, '0');
            progress.style.width = ((current + 1) / TOTAL * 100) + '%';

            // Scene-specific animations
            animateScene(current);

            if (auto) scheduleNext();
          }

          function scheduleNext() {
            clearTimeout(timer);
            timer = setTimeout(() => {
              if (auto) goTo(current + 1);
            }, DELAYS[current]);
          }

          function animateScene(n) {
            if (n === 1) { // pain items
              document.querySelectorAll('.pain-item').forEach((el, i) => {
                el.style.opacity = '0'; el.style.transform = 'translateX(-40px)';
                setTimeout(() => { el.style.transition = 'all .6s ease'; el.style.opacity = '1'; el.style.transform = 'translateX(0)'; }, 200 + i * 300);
              });
            }
            if (n === 2) { // feature cards
              document.querySelectorAll('.feat-card').forEach((el, i) => {
                el.classList.remove('show');
                setTimeout(() => { el.classList.add('show'); }, 200 + i * 200);
              });
            }
            if (n >= 3 && n <= 8) { // screen scenes (4-9 in 0-indexed: 3-8)
              const id = 'mock' + (n + 1);
              const m = document.getElementById(id);
              if (m) {
                m.style.opacity = '0'; m.style.transform = 'translateX(50px) perspective(1000px) rotateY(-8deg)';
                setTimeout(() => {
                  m.classList.add('show'); m.style.transition = 'all .9s cubic-bezier(.16,1,.3,1)';
                  m.style.opacity = '1'; m.style.transform = 'translateX(0) perspective(1000px) rotateY(-3deg)';
                }, 300);
              }
              // animate text
              ['.screen-badge', '.screen-title', '.screen-desc', '.screen-stats'].forEach((sel, i) => {
                const el = scenes[n].querySelector(sel);
                if (el) {
                  el.style.opacity = '0'; el.style.transform = 'translateY(20px)';
                  setTimeout(() => { el.style.transition = 'all .6s ease'; el.style.opacity = '1'; el.style.transform = 'translateY(0)'; }, 200 + i * 150);
                }
              });
            }
            if (n === 9) { // counters
              document.querySelectorAll('.big-stat').forEach((el, i) => {
                el.style.opacity = '0'; el.style.transform = 'translateY(20px)';
                setTimeout(() => { el.style.transition = 'all .6s ease'; el.style.opacity = '1'; el.style.transform = 'translateY(0)'; }, 200 + i * 200);
              });
              animateCounter('cnt1', 96, 2000, '');
              animateCounter('cnt2', 59995, 2000, '');
              animateCounter('cnt3', 57214, 2000, '$');
              animateCounter('cnt4', 30, 2000, '+', '%');
            }
          }

          function animateCounter(id, target, dur, prefix = '', suffix = '') {
            const el = document.getElementById(id);
            if (!el) return;
            const start = Date.now();
            const tick = () => {
              const elapsed = Date.now() - start;
              const progress = Math.min(elapsed / dur, 1);
              const val = Math.floor(easeOut(progress) * target);
              el.textContent = prefix + val.toLocaleString() + suffix;
              if (progress < 1) requestAnimationFrame(tick);
            };
            requestAnimationFrame(tick);
          }
          function easeOut(t) { return 1 - Math.pow(1 - t, 3); }

          // Controls
          document.getElementById('prevBtn').onclick = () => { if (auto) { auto = false; clearTimeout(timer); document.getElementById('autoBtn').classList.remove('active-btn'); } goTo(current - 1); };
          document.getElementById('nextBtn').onclick = () => { if (auto) { auto = false; clearTimeout(timer); document.getElementById('autoBtn').classList.remove('active-btn'); } goTo(current + 1); };
          document.getElementById('autoBtn').onclick = () => {
            auto = !auto;
            document.getElementById('autoBtn').classList.toggle('active-btn', auto);
            document.getElementById('autoBtn').textContent = auto ? '⏵ Auto' : '⏸ Pausado';
            if (auto) scheduleNext();
          };

          // Keyboard
          document.addEventListener('keydown', e => {
            if (e.key === 'ArrowRight') goTo(current + 1);
            if (e.key === 'ArrowLeft') goTo(current - 1);
            if (e.key === ' ') { auto = !auto; document.getElementById('autoBtn').click(); }
          });


          // Lex avatar animation
          function animateLex() {
            const lexImgs = [
              'data:image/png;base64,',
              'data:image/png;base64,',
              'data:image/png;base64,',
              'data:image/png;base64,'
            ];
            let li = 0;
            const lexAvatar = document.querySelector('#s8 .mockup-screen img[style*="40px"]');
            if (!lexAvatar) return;
            setInterval(() => {
              li = (li + 1) % lexImgs.length;
              lexAvatar.src = lexImgs[li];
            }, 2000);
          }
          animateLex();

          // Init
          progress.style.width = (1 / TOTAL * 100) + '%';
          scheduleNext();

          // Audio Logic
          const bgMusic = document.getElementById('bg-music');
          const audioControl = document.getElementById('audio-control');
          let isMuted = true;

          // Set initial volume to 0 for fade in
          bgMusic.volume = 0;

          audioControl.addEventListener('click', () => {
            if (isMuted) {
              // Unmute and play (if not already playing)
              const playPromise = bgMusic.play();
              if (playPromise !== undefined) {
                playPromise.catch(e => debugLog('Audio play failed:', e));
              }

              // Fade in
              let vol = 0;
              const fadeInterval = setInterval(() => {
                if (vol < 0.4) {
                  vol += 0.05;
                  // Fix precision issues
                  bgMusic.volume = Math.min(Math.round(vol * 100) / 100, 0.4);
                } else {
                  clearInterval(fadeInterval);
                }
              }, 100);

              audioControl.innerHTML = '🔊';
              audioControl.classList.remove('muted');
              isMuted = false;
            } else {
              // Fade out
              let vol = bgMusic.volume;
              const fadeInterval = setInterval(() => {
                if (vol > 0) {
                  vol -= 0.05;
                  // Fix precision issues
                  bgMusic.volume = Math.max(Math.round(vol * 100) / 100, 0);
                } else {
                  clearInterval(fadeInterval);
                  bgMusic.pause();
                }
              }, 100);

              audioControl.innerHTML = '🔇';
              audioControl.classList.add('muted');
              isMuted = true;
            }
          });

          // Start auto-play attempt on interaction if not already started
          document.body.addEventListener('click', function initAudio() {
            if (isMuted) return; // Only play if user has explicitly unmuted
            const playPromise = bgMusic.play();
            if (playPromise !== undefined) {
              playPromise.catch(e => debugLog('Autoplay prevented'));
            }
            document.body.removeEventListener('click', initAudio);
          }, { once: true });

          // Initialize presentation
          document.addEventListener('DOMContentLoaded', () => {
            goTo(0);
            calcular(); // Initial calculation for calculator
          });

          // ==========================================
          // CALCULATOR LOGIC
          // ==========================================
          const elCargas = document.getElementById('cargas');
          const elIngreso = document.getElementById('ingreso');
          const elCombustible = document.getElementById('combustible');
          const elGastos = document.getElementById('gastos');
          const elMalas = document.getElementById('malas');
          const elHoras = document.getElementById('horas');

          const elCargasDisplay = document.getElementById('cargas-display');
          const elMalasDisplay = document.getElementById('malas-display');
          const elHorasDisplay = document.getElementById('horas-display');

          function fmt(n) {
            return '$' + Math.round(n).toLocaleString('es-US');
          }

          function calcular() {
            const cargas = parseInt(elCargas?.value) || 0;
            const ingresoPorCarga = parseFloat(elIngreso?.value) || 0;
            const combustible = parseFloat(elCombustible?.value) || 0;
            const gastos = parseFloat(elGastos?.value) || 0;
            const pctMalas = (parseInt(elMalas?.value) || 0) / 100;
            const horasPerdidas = parseInt(elHoras?.value) || 0;

            const ingresoTotal = cargas * ingresoPorCarga;
            const gastosTotales = combustible + gastos;
            const gananciaNeta = ingresoTotal - gastosTotales;

            const cargasMalas = Math.round(cargas * pctMalas);
            const perdidaPorMalas = cargasMalas * ingresoPorCarga * 0.30;

            const valorHora = gananciaNeta > 0 ? (gananciaNeta / (cargas * 8)) : 15;
            const perdidaPorHoras = horasPerdidas * 4 * valorHora; // 4 semanas

            const perdidaTotal = perdidaPorMalas + perdidaPorHoras;
            const pctPerdida = ingresoTotal > 0 ? Math.min((perdidaTotal / ingresoTotal) * 100, 100) : 0;

            const mejoraCon = perdidaTotal * 0.70 + (ingresoTotal * 0.12);
            const gananciaConSmart = gananciaNeta + mejoraCon;

            if (document.getElementById('ingreso-total')) document.getElementById('ingreso-total').textContent = fmt(ingresoTotal);
            if (document.getElementById('ganancia-neta')) document.getElementById('ganancia-neta').textContent = fmt(gananciaNeta);
            if (document.getElementById('perdida')) document.getElementById('perdida').textContent = fmt(perdidaTotal);
            if (document.getElementById('con-smart')) document.getElementById('con-smart').textContent = fmt(gananciaConSmart);
            if (document.getElementById('perdida-bar')) document.getElementById('perdida-bar').style.width = Math.min(pctPerdida, 100) + '%';

            let msg = '';
            const margenReal = ingresoTotal > 0 ? (gananciaNeta / ingresoTotal * 100) : 0;

            if (perdidaTotal > 3000) {
              msg = `Estás perdiendo <strong>${fmt(perdidaTotal)} cada mes</strong> — eso es ${fmt(perdidaTotal * 12)} al año. Con Smart Load, recuperarías la mayoría de eso al tomar mejores decisiones en cada carga.`;
            } else if (margenReal < 25) {
              msg = `Tu margen neto es de solo <strong>${margenReal.toFixed(0)}%</strong>. Con un margen tan ajustado, cada carga mala que aceptas te cuesta mucho. Smart Load te ayuda a filtrar esas cargas antes de comprometerte.`;
            } else if (pctMalas > 0.3) {
              msg = `Con <strong>${Math.round(pctMalas * 100)}% de cargas malas</strong> estás trabajando de más por menos dinero. Imagina reducir eso a la mitad — tu ganancia crecería sin hacer más cargas.`;
            } else if (horasPerdidas >= 8) {
              msg = `Estás perdiendo <strong>${horasPerdidas} horas semanales</strong> en papeleo. Con Smart Load automatizas eso y recuperas tiempo real para más cargas o descanso.`;
            } else {
              msg = `Tu operación tiene buen potencial. <strong>Optimizando el ${Math.round(pctMalas * 100)}% de cargas que no son ideales</strong> podrías incrementar tus ganancias un 12-20% sin aumentar costos.`;
            }

            if (document.getElementById('lex-mensaje')) document.getElementById('lex-mensaje').innerHTML = msg;
          }

          function pauseAuto() {
            auto = false;
            clearTimeout(timer);
          }

          if (elCargas) elCargas.addEventListener('input', () => { elCargasDisplay.textContent = elCargas.value + ' cargas'; pauseAuto(); calcular(); });
          if (elMalas) elMalas.addEventListener('input', () => { elMalasDisplay.textContent = elMalas.value + '%'; pauseAuto(); calcular(); });
          if (elHoras) elHoras.addEventListener('input', () => { elHorasDisplay.textContent = elHoras.value + ' hrs'; pauseAuto(); calcular(); });

          [elIngreso, elCombustible, elGastos].forEach(el => {
            if (el) el.addEventListener('input', () => { pauseAuto(); calcular(); });
          });
        